mapper.select:
SELECT o.id, o.employee_id, o.overtime_date, o.start_time, o.end_time, o.hours, o.reason, o.created_at, o.updated_at, e.employee_no, e.name AS employee_name, d.department_name FROM overtime_record o INNER JOIN employee e ON o.employee_id = e.id LEFT JOIN department d ON e.department_id = d.id
AND e.status = AND (o.reason IS NULL OR o.reason NOT LIKE CONCAT(, '%'))
AND e.employee_no = #{employeeNo}
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.department_id = #{departmentId}
AND o.overtime_date >= #{startDate}
AND o.overtime_date <= #{endDate}
ORDER BY o.overtime_date DESC, o.id DESC

SELECT id, employee_id, overtime_date, start_time, end_time, hours, reason, created_at, updated_at
FROM overtime_record
WHERE id = #{id}

mapper.update:
UPDATE overtime_record
SET reason = CONCAT(, COALESCE(reason, ''))
WHERE id = #{id}
